# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3

def lambda_handler(event, context):
    sns_client = boto3.client('sns')
    
    # Extract message content and topic ARN from event data
    message_content = event['message']
    topic_arn = event['topicArn']
    notification_type = event.get('notificationType', 'DEFAULT')

    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=message_content,
            Subject=f'Notification of type: {notification_type}',
            MessageAttributes={
                'NotificationType': {
                    'DataType': 'String',
                    'StringValue': notification_type
                }
            }
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Message published successfully', 'response': response})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'message': 'Failed to publish message', 'error': str(e)})
        }